from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple (without subject repetition)
    def _clause(p: str, o: str) -> str:
        """Build a clause that describes the triple without repeating the subject."""
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"has a {idx.lower()} runway that is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"has a {idx.lower()} runway that is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"has a runway named {o}"
        if p == "runwayLength":
            return f"has a runway length of {o}"
        # Runway surface types
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            return f"has a {idx.lower()} runway surface of {o}"
        # Runway numbers
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            return f"has a {idx.lower()} runway number {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"has ICAO code {o}"
        if p == "locationIdentifier":
            return f"has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"is owned by {o}"
        if p == "largestCity":
            return f"has {o} as the largest city"
        if p == "capital":
            return f"has {o} as its capital"
        if p == "language" or p == "officialLanguage":
            return f"has official language {o}"
        if p == "leader":
            return f"has leader {o}"
        if p == "leaderTitle":
            return f"with leader title {o}"
        if p == "leaderParty":
            return f"whose leader belongs to the {o} party"
        # Native name
        if p == "nativeName":
            return f"known as {o}"
        # Administrative info
        if p == "administrativeArrondissement":
            return f"in the administrative arrondissement of {o}"
        if p == "mayor":
            return f"has mayor {o}"
        if p == "currency":
            return f"uses the {o}"
        if p == "demonym":
            return f"where people are called {o}"
        if p == "regionServed":
            return f"serves the {o} region"
        if p == "hubAirport":
            return f"has {o} as a hub airport"
        if p == "headquarter":
            return f"has headquarters at {o}"
        if p == "foundedBy":
            return f"founded by {o}"
        if p == "foundingYear":
            return f"founded in {o}"
        if p == "postalCode":
            return f"with postal code {o}"
        if p == "areaCode":
            return f"with area code {o}"
        if p == "ceremonialCounty":
            return f"in the ceremonial county of {o}"
        if p == "countySeat":
            return f"county seat is {o}"
        if p == "chief":
            return f"chief is {o}"
        if p == "jurisdiction":
            return f"with jurisdiction over {o}"
        if p == "city":
            return f"is located in {o}"
        # Fallback for any other predicate
        return f"with {p} {o}"

    # Group triples by subject to build more coherent sentences
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Build clauses for each subject
    all_clauses: list[str] = []
    for subject, subj_triples in subject_triples.items():
        # Build clauses for this subject
        subj_clauses: list[str] = []
        for t in subj_triples:
            clause = _clause(t.subject, t.predicate, _clean(t.object))
            # Remove the subject from the clause for relative clause building
            if clause.startswith(subject):
                clause = clause[len(subject):].strip()
                if clause.startswith("is") or clause.startswith("has") or clause.startswith("serves"):
                    subj_clauses.append(clause)
                else:
                    subj_clauses.append("which " + clause)
            else:
                subj_clauses.append(clause)

        # Combine clauses for this subject into one statement
        if len(subj_clauses) == 1:
            all_clauses.append(f"{subject} {subj_clauses[0]}.")
        else:
            # Build complex sentence for this subject
            parts = [f"{subject} {subj_clauses[0]}"]
            for clause in subj_clauses[1:]:
                if clause.startswith("which"):
                    parts.append(f", {clause}")
                else:
                    parts.append(f", which {clause}")
            all_clauses.append("".join(parts) + ".")

    # Combine all subject statements into one sentence
    if len(all_clauses) == 1:
        sentence = all_clauses[0]
    else:
        # Link multiple subjects with appropriate connectors
        sentence = all_clauses[0].rstrip(".")
        for clause in all_clauses[1:]:
            sentence += ", and " + clause.lower().capitalize()
        sentence = sentence.rstrip(".") + "."

    # Ensure first character is capitalized
    if sentence and sentence[0].islower():
        sentence = sentence[0].upper() + sentence[1:]

    return sentence

# EVOLVE-BLOCK-END

